questionvariables.text:
/* Random set selection: 1..4 */
set: rand(4)+1;

Z0: if set=1 then 50 else if set=2 then 75 else if set=3 then 100 else 50;
RL: if set=1 then 100 else if set=2 then 30 else if set=3 then 200 else 25;
XL: if set=1 then 50 else if set=2 then -40 else if set=3 then 100 else -25;
lambda_m: if set=1 then 0.48 else if set=2 then 0.36 else if set=3 then 0.60 else 0.72;

/* Complex load */
ZL: RL + %i*XL;

/* Reflection coefficient */
Gamma_complex: (ZL - Z0) / (ZL + Z0);
ta1: float(abs(Gamma_complex));                           /* |Gamma| */
ta2: float(carg(Gamma_complex) * 180 / %pi);             /* theta_Gamma in degrees */

/* VSWR */
ta3: float((1 + ta1) / (1 - ta1));

/* Phase constant */
beta: float(2 * %pi / lambda_m);

/* First voltage maximum from load: d_max = theta_Gamma/(2*beta) if theta_Gamma > 0, else (theta_Gamma+2*pi)/(2*beta) */
theta_rad: float(carg(Gamma_complex));
ta4_raw: float(theta_rad / (2 * beta));
ta4: if is(ta4_raw >= 0) then ta4_raw else float(ta4_raw + lambda_m/2);   /* ensure positive */

/* First voltage minimum: d_min = d_max + lambda/4 (mod lambda/2) or d_max - lambda/4 */
ta5_raw: float(ta4 + lambda_m/4);
ta5: if is(ta5_raw >= lambda_m/2) then float(ta5_raw - lambda_m/2) else ta5_raw;

/* Display variables */
Z0_disp: float(Z0);
RL_disp: float(RL);
XL_disp: float(XL);
lambda_disp: float(lambda_m * 100);  /* in cm */

/* MCQ Part (f): If Z_L = Z_0, |Gamma| = ? */
ta6: random_permutation([[1, true, "0"], [2, false, "0.5"], [3, false, "1"], [4, false, "Undefined"]]);
ta6_correct: 1;

/* MCQ Part (g): What does VSWR=1 mean? */
ta7: random_permutation([[1, true, "The line is perfectly matched — no reflections occur and all power is delivered to the load"], [2, false, "The line has maximum reflections and no power reaches the load"], [3, false, "The characteristic impedance equals zero"], [4, false, "The line is open-circuited"]]);
ta7_correct: 1;

/* Part (h): maximum RL for VSWR <= 2 (purely resistive, RL > Z0) */
ta8: float(2 * Z0);

/* Display-friendly VSWR (rounded to 2 decimal places) */
ta3_disp: float(round(ta3 * 100) / 100);

/* Part (i): radio MCQ — does the complex load satisfy VSWR <= 2? */
/* Correct answer depends on whether ta3 is actually <= 2 */
ta9_q3: random_permutation(if is(ta3 <= 2.0) then
    [[1,true,"Yes — the complex load has VSWR ≤ 2, so the constraint is satisfied"],
     [2,false,"No — the complex load has VSWR > 2, so matching is needed"],
     [3,false,"Cannot determine — the formula R_L ≤ 2·Z₀ only applies to resistive loads"],
     [4,false,"Yes — because the resistive part of Z_L is less than 2·Z₀"]]
  else
    [[1,false,"Yes — the complex load has VSWR ≤ 2, so the constraint is satisfied"],
     [2,true,"No — the complex load has VSWR > 2, so matching is needed"],
     [3,false,"Cannot determine — the formula R_L ≤ 2·Z₀ only applies to resistive loads"],
     [4,false,"Yes — because the resistive part of Z_L is less than 2·Z₀"]]);
ta9_q3_correct: if is(ta3 <= 2.0) then 1 else 2;

/* Part (j): notes input — auto-graded as pass */
ta10_q3: "See model answer in the worked solution.";
